module frequency_divider(  
    input clk,  
    input reset,  
    output reg divided_clk  
);  
    reg [1:0] countdown;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            countdown <= 2'b00;  
            divided_clk <= 1'b0;  
        end else begin  
            countdown <= countdown + 1;  
            if (countdown == 2'b11) begin  
                divided_clk <= ~divided_clk;  
            end  
        end  
    end  
endmodule
